#[tokio::test]
async fn test_string_pattern_validation_fail() {
    // Tests string field with regex pattern constraint failure
    let expected_body = r#"{"detail":"1 validation error in request","errors":[{"ctx":{"pattern":"^[A-Z]{3}[0-9]{4}$"},"input":"ABC-123","loc":["body","sku"],"msg":"String should match pattern '^[A-Z]{3}[0-9]{4}$'","type":"string_pattern_mismatch"}],"status":422,"title":"Request Validation Failed","type":"https://spikard.dev/errors/validation-error"}"#.to_string();
    let mut app = spikard::App::new();
    app.route(
        spikard::post("/items/validated"),
        move |_ctx: spikard::RequestContext| {
            let body = expected_body.clone();
            async move {
                Ok(axum::http::Response::builder()
                    .status(422u16)
                    .header("content-type", "application/json")
                    .body(axum::body::Body::from(body))
                    .unwrap())
            }
        },
    )
    .unwrap();
    let router = app.into_router().unwrap();
    let server = axum_test::TestServer::new(router);
    let response = server
        .post("/items/validated")
        .add_header(r#"Content-Type"#, r#"application/json"#)
        .bytes(bytes::Bytes::copy_from_slice(
            r#"{"name":"Item","sku":"ABC-123"}"#.as_bytes(),
        ))
        .await;
    assert_eq!(response.status_code().as_u16(), 422u16);
}

